export function getTeamMeta(slug: string): TeamMeta | null {
  const s = String(slug ?? "").trim().toLowerCase();
  if (!s) return null;
  if (TEAM_META[s]) return TEAM_META[s];

  const aliases: Record<string, string> = {
    "miami-fl": "miami",
    umass: "massachusetts",
  };
  const canonical = aliases[s];
  return canonical ? (TEAM_META[canonical] ?? null) : null;
}

